// ---- Anthropic API helpers --------------------------------------------------

async function callClaude(prompt, useSearch = false, costTier = "heavy") {
  let finalPrompt = prompt;
  if (window.currentCompanyDataRoomText) {
    if (!prompt.includes("Proprietary Data Room contents")) {
      finalPrompt = prompt + window.currentCompanyDataRoomText;
    }
  }

  // Append a strict instruction to prevent truncation/shortcuts/summarizations
  const instruction = "\n\nCRITICAL SYSTEM REQUIREMENT: You must generate the requested document in its entirety. Do NOT omit any section, do NOT use placeholders (like '[Insert detailed overview...]' or '...'), and do NOT truncate lists or tables. Write out all parts in full analytical detail. Ensure all sections are completely written out from start to finish.";
  finalPrompt = finalPrompt + instruction;

  // Retrieve model tier setting from storage
  const modelTier = localStorage.getItem("anthropic_model_tier") || "auto";
  let selectedModel = "claude-sonnet-4-6"; // default Sonnet tier for the platform
  if (!useSearch) {
    if (modelTier === "haiku") {
      selectedModel = "claude-3-5-haiku-20241022";
    } else if (modelTier === "auto") {
      selectedModel = costTier === "light" ? "claude-3-5-haiku-20241022" : "claude-sonnet-4-6";
    }
  }

  const body = {
    model: selectedModel,
    max_tokens: 4000,
  };
  if (useSearch) body.tools = [{ type: "web_search_20250305", name: "web_search" }];

  // Enable prompt caching for larger prompts (typically > 2000 chars) to save compute costs
  if (finalPrompt.length > 2000) {
    body.messages = [
      {
        role: "user",
        content: [
          {
            type: "text",
            text: finalPrompt,
            cache_control: { type: "ephemeral" }
          }
        ]
      }
    ];
  } else {
    body.messages = [{ role: "user", content: finalPrompt }];
  }
  
  // Retrieve local API key from storage
  const localKey = localStorage.getItem("anthropic_api_key") || "";
  const headers = { "Content-Type": "application/json" };
  if (localKey) {
    headers["X-Anthropic-API-Key"] = localKey;
  }
  
  let betas = [];
  if (useSearch) betas.push("web-search-2025-03-05");
  if (finalPrompt.length > 2000) betas.push("prompt-caching-2024-07-31");
  
  if (betas.length > 0) {
    headers["anthropic-beta"] = betas.join(",");
  }

  // Request forwarded to the local proxy to bypass browser CORS
  const res = await fetch("/api/anthropic", {
    method: "POST",
    headers: headers,
    body: JSON.stringify(body),
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message || "API error");
  return (data.content || [])
    .filter((b) => b.type === "text")
    .map((b) => b.text)
    .join("\n");
}

function parseJSON(text) {
  let clean = text.replace(/```json|```/g, "").trim();
  
  // Find all indices of '{' and '['
  let candidates = [];
  for (let i = 0; i < clean.length; i++) {
    if (clean[i] === '{' || clean[i] === '[') {
      candidates.push(i);
    }
  }
  
  let lastError = null;
  
  for (const startIdx of candidates) {
    let sub = clean.slice(startIdx);
    
    // Balance braces/brackets starting from startIdx
    let stack = [];
    let inString = false;
    let escape = false;
    let closedClean = "";
    
    for (let i = 0; i < sub.length; i++) {
      const char = sub[i];
      closedClean += char;
      if (escape) {
        escape = false;
      } else if (char === '\\') {
        escape = true;
      } else if (char === '"') {
        inString = !inString;
      } else if (!inString) {
        if (char === '{') {
          stack.push('}');
        } else if (char === '[') {
          stack.push(']');
        } else if (char === '}') {
          if (stack.length && stack[stack.length - 1] === '}') {
            stack.pop();
          }
        } else if (char === ']') {
          if (stack.length && stack[stack.length - 1] === ']') {
            stack.pop();
          }
        }
      }
      if (stack.length === 0 && (closedClean.endsWith('}') || closedClean.endsWith(']'))) {
        break;
      }
    }
    
    if (inString) {
      closedClean += '"';
    }
    while (stack.length) {
      closedClean += stack.pop();
    }
    
    let repaired = closedClean;
    // 1. Auto-repair missing commas between key-value pairs
    repaired = repaired.replace(/([}\]"\w])(\s+)("[\w\-]+"\s*:)/g, '$1,$2$3');
    // Auto-repair missing commas between objects in arrays
    repaired = repaired.replace(/(\})(\s*)(\{)/g, '$1,$2$3');
    
    // 2. Quote repair: escape unescaped internal quotes
    let quoteRepaired = "";
    inString = false;
    escape = false;
    
    for (let i = 0; i < repaired.length; i++) {
      const char = repaired[i];
      if (escape) {
        quoteRepaired += char;
        escape = false;
        continue;
      }
      if (char === '\\') {
        quoteRepaired += char;
        escape = true;
        continue;
      }
      if (char === '"') {
        const before = repaired.slice(0, i).trim();
        const after = repaired.slice(i + 1).trim();
        const lastChar = before.slice(-1);
        const nextChar = after[0];
        
        let isStructural = false;
        if (inString) {
          isStructural = nextChar === ":" || nextChar === "," || nextChar === "}" || nextChar === "]";
        } else {
          isStructural = lastChar === "{" || lastChar === "[" || lastChar === "," || lastChar === ":";
        }
        
        if (isStructural) {
          quoteRepaired += '"';
          inString = !inString;
        } else {
          if (inString) {
            quoteRepaired += '\\"';
          } else {
            quoteRepaired += '"';
          }
        }
      } else {
        quoteRepaired += char;
      }
    }
    
    // 3. Repair newlines/tabs inside strings
    const repairNewlines = (str) => {
      let rep = "";
      let inStr = false;
      let esc = false;
      for (let i = 0; i < str.length; i++) {
        const char = str[i];
        if (esc) {
          rep += char;
          esc = false;
        } else if (char === '\\') {
          rep += char;
          esc = true;
        } else if (char === '"') {
          rep += char;
          inStr = !inStr;
        } else if (inStr && char === '\n') {
          rep += '\\n';
        } else if (inStr && char === '\r') {
          rep += '\\r';
        } else if (inStr && char === '\t') {
          rep += '\\t';
        } else {
          rep += char;
        }
      }
      return rep.replace(/,\s*([}\]])/g, '$1');
    };
    
    try {
      return JSON.parse(repairNewlines(quoteRepaired));
    } catch (err) {
      lastError = err;
    }
  }
  
  throw new Error("Could not find JSON object or array boundaries in response. Raw response: " + text.slice(0, 1000) + (lastError ? ` (Parse error: ${lastError.message})` : ""));
}

async function uploadAssetFile(file) {
  const headers = {
    "X-Filename": encodeURIComponent(file.name),
    "Content-Type": file.type || "application/octet-stream"
  };
  const res = await fetch("/api/upload", {
    method: "POST",
    headers: headers,
    body: file
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message || "Upload failed");
  return {
    name: data.name || file.name,
    url: data.url,
    ts: Date.now()
  };
}

// ---- Score radar glyph (the "seal") ----------------------------------------

function RadarSeal({ scores, size = 56, stroke = BLUE }) {
  const c = size / 2;
  const r = c - 4;
  const pts = (vals) =>
    DIMS.map((d, i) => {
      const a = -Math.PI / 2 + (i * 2 * Math.PI) / DIMS.length;
      const v = (vals ? Math.max(0.4, Number(vals[d.key]) || 0) / 5 : 1) * r;
      return `${c + v * Math.cos(a)},${c + v * Math.sin(a)}`;
    }).join(" ");
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <polygon points={pts(null)} fill="none" stroke={LINE} strokeWidth="1" />
      <polygon points={pts(scores)} fill={stroke} fillOpacity="0.14" stroke={stroke} strokeWidth="1.5" />
    </svg>
  );
}

function compositeScore(scores) {
  if (!scores) return null;
  const vals = DIMS.map((d) => Number(scores[d.key]) || 0);
  const sum = vals.reduce((a, b) => a + b, 0);
  return Math.round((sum / (DIMS.length * 5)) * 100) / 20; // scale back to 0-5
}

function founderQualitativeAverage(obj) {
  if (!obj) return null;
  const s = obj.scores || obj;
  if (!s) return null;
  const vals = [s.ambition, s.execution, s.resilience, s.chemistry, s.hungerness, s.domainExpertise].map(Number).filter(v => !isNaN(v));
  if (vals.length === 0) return null;
  return vals.reduce((a, b) => a + b, 0) / vals.length;
}

function combinedFounderCompanyScore(c) {
  const defScore = compositeScore(c?.scores);
  const fAvg = founderQualitativeAverage(c?.founderAssessment);
  if (defScore !== null && fAvg !== null) {
    return (defScore + fAvg) / 2;
  }
  return defScore !== null ? defScore : fAvg;
}

function getTamValue(c) {
  if (!c?.marketStudy?.businessModel) return 0;
  return (c.marketStudy.businessModel.tamUnits || 0) * (c.marketStudy.businessModel.estimatedAcv || 0);
}

function formatCompactUSD(val) {
  if (val == null || isNaN(val) || val === 0) return "—";
  if (val >= 1e9) {
    return "$" + (val / 1e9).toFixed(1).replace(/\.0$/, "") + "B";
  }
  if (val >= 1e6) {
    return "$" + (val / 1e6).toFixed(1).replace(/\.0$/, "") + "M";
  }
  if (val >= 1e3) {
    return "$" + (val / 1e3).toFixed(1).replace(/\.0$/, "") + "k";
  }
  return "$" + val;
}

function scoreColor(v) {
  if (v == null) return FADE;
  if (v >= 3.6) return BLUE;
  if (v >= 2.6) return AMBER;
  return RUST;
}

