const Tag = ({ children, color = INK }) => (
  <span style={{ fontFamily: fontStack.mono, fontSize: 10, padding: "2px 7px", border: `1px solid ${color}`, color, borderRadius: 999, marginRight: 5, whiteSpace: "nowrap" }}>
    {children}
  </span>
);

const VerificationBadge = ({ status, onClick }) => {
  let title = "Unverified LinkedIn link. Click to verify.";
  let content = "🔘";
  let cursor = "pointer";
  let opacity = 0.7;

  if (status === "verifying") {
    title = "Verifying link via AI search...";
    content = "⏳";
    cursor = "wait";
    opacity = 1;
  } else if (status === "verified") {
    title = "LinkedIn link verified as active & accurate!";
    content = "✅";
    cursor = "default";
    opacity = 1;
  } else if (status === "corrected") {
    title = "LinkedIn link was incorrect/dead, but corrected by AI search!";
    content = "✨";
    cursor = "default";
    opacity = 1;
  } else if (status === "not_found") {
    title = "Could not find active LinkedIn profile for this contact. Click to retry.";
    content = "⚠️";
    cursor = "pointer";
    opacity = 1;
  }

  return (
    <span
      onClick={onClick}
      title={title}
      style={{
        cursor,
        opacity,
        display: "inline-flex",
        alignItems: "center",
        justifyContent: "center",
        width: 20,
        height: 20,
        fontSize: 13,
        userSelect: "none",
        transition: "all 0.15s ease",
      }}
      onMouseEnter={(e) => {
        if (cursor === "pointer") e.currentTarget.style.transform = "scale(1.2)";
      }}
      onMouseLeave={(e) => {
        if (cursor === "pointer") e.currentTarget.style.transform = "scale(1)";
      }}
    >
      {content}
    </span>
  );
};


const DropZone = ({ onFileSelected, file, loading, progressText }) => {
  const [dragOver, setDragOver] = useState(false);
  const inputRef = useRef(null);

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragover" || e.type === "dragenter") {
      setDragOver(true);
    } else if (e.type === "dragleave" || e.type === "drop") {
      setDragOver(false);
    }
  };

  const handleDrop = async (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragOver(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const droppedFile = e.dataTransfer.files[0];
      if (droppedFile.type === "application/pdf" || droppedFile.name.endsWith(".pdf")) {
        onFileSelected({ target: { files: [droppedFile] } });
      } else {
        alert("Only PDF files are supported.");
      }
    }
  };

  const handleChange = (e) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelected(e);
    }
  };

  return (
    <div
      onDragEnter={handleDrag}
      onDragOver={handleDrag}
      onDragLeave={handleDrag}
      onDrop={handleDrop}
      onClick={() => inputRef.current?.click()}
      style={{
        border: `2px dashed ${dragOver ? BLUE : LINE}`,
        borderRadius: 4,
        background: dragOver ? "rgba(31, 45, 203, 0.04)" : CARD,
        padding: "20px 14px",
        textAlign: "center",
        cursor: "pointer",
        transition: "all 0.15s ease-in-out",
        boxSizing: "border-box",
        width: "100%"
      }}
    >
      <input
        ref={inputRef}
        type="file"
        accept=".pdf"
        onChange={handleChange}
        style={{ display: "none" }}
      />
      <div style={{ fontSize: 22, marginBottom: 6 }}>📄</div>
      <div style={{ fontSize: 13, fontWeight: 500, color: dragOver ? BLUE : INK }}>
        {dragOver ? "Drop your pitch deck here" : "Drag & drop Pitch Deck PDF here, or click to browse"}
      </div>
      <div style={{ fontSize: 11, color: FADE, marginTop: 4 }}>
        Only PDF pitch decks are supported (parsed locally in browser)
      </div>
      
      {loading && (
        <div style={{ fontSize: 11.5, color: BLUE, marginTop: 8, fontFamily: fontStack.mono }}>
          {progressText || "Processing PDF..."}
        </div>
      )}
      
      {file && !loading && (
        <div style={{ fontSize: 11, color: "#10B981", marginTop: 8, fontFamily: fontStack.mono, wordBreak: "break-all" }}>
          ✓ Ingested: {file.name} ({Math.round(file.size / 1024)} KB)
        </div>
      )}
    </div>
  );
};

const deduplicateCompanies = (list) => {
  const merged = [];
  (list || []).forEach((item) => {
    if (!item) return;
    const isDup = (c) => {
      if (item.url && c.url && typeof item.url === "string" && typeof c.url === "string") {
        const clean1 = item.url.toLowerCase().replace(/^https?:\/\/(www\.)?/, "").trim();
        const clean2 = c.url.toLowerCase().replace(/^https?:\/\/(www\.)?/, "").trim();
        if (clean1 && clean2 && (clean1 === clean2 || clean1.includes(clean2) || clean2.includes(clean1))) {
          return true;
        }
      }
      return c.name && item.name && typeof c.name === "string" && typeof item.name === "string" && 
             c.name.toLowerCase().trim() === item.name.toLowerCase().trim();
    };
    const existingIndex = merged.findIndex(isDup);
    if (existingIndex !== -1) {
      merged[existingIndex] = {
        ...merged[existingIndex],
        ...item,
        id: merged[existingIndex].id,
        geo: item.geo || merged[existingIndex].geo || "",
        priority: (item.priority && item.priority !== "Medium") ? item.priority : (merged[existingIndex].priority || "Medium"),
        founders: (item.founders && item.founders.length > 0) ? item.founders : (merged[existingIndex].founders || []),
        notes: [...(merged[existingIndex].notes || []), ...(item.notes || [])],
        scores: item.scores || merged[existingIndex].scores,
        rationale: item.scores ? item.rationale : merged[existingIndex].rationale
      };
    } else {
      merged.push(item);
    }
  });
  return merged;
};

const cleanAndStandardizeInvestors = (list) => {
  if (!Array.isArray(list)) return [];
  
  const stageKeywords = ["seed", "pre", "series", "growth", "venture", "early", "late", "stage", "all", "a", "b", "c", "d"];

  return list.map(inv => {
    if (!inv) return null;
    let geo = String(inv.geo || "").trim();
    let city = String(inv.city || "").trim();
    let stage = String(inv.stage || "").trim();
    let notes = String(inv.notes || "").trim();

    // 1. Clean Stage Focus: check if it contains a person's name
    if (stage) {
      const words = stage.split(/\s+/).map(w => w.replace(/[^\w]/g, ""));
      const hasStageKeyword = words.some(w => stageKeywords.includes(w.toLowerCase()));
      
      // If it doesn't look like a stage focus but looks like a name
      if (!hasStageKeyword && words.length >= 2) {
        const secondaryContactName = stage;
        stage = "Seed"; // Reset to standard fallback
        const contactNote = `Secondary Contact: ${secondaryContactName}`;
        if (notes) {
          if (!notes.includes(contactNote)) {
            notes = notes + "\n\n" + contactNote;
          }
        } else {
          notes = contactNote;
        }
      }
    }

    // 2. Clean Geography/Country: Map to standard main countries/regions
    if (geo) {
      const geoLower = geo.toLowerCase();
      if (geoLower.includes("us") || geoLower.includes("united states") || geoLower.includes("america") || geoLower.includes("sf") || geoLower.includes("california") || geoLower.includes("boston") || geoLower.includes("new york") || geoLower.includes("ny")) {
        geo = "United States";
      } else if (geoLower.includes("uk") || geoLower.includes("united kingdom") || geoLower.includes("london") || geoLower.includes("britain")) {
        geo = "United Kingdom";
      } else if (geoLower.includes("nordic") || geoLower.includes("sweden") || geoLower.includes("norway") || geoLower.includes("denmark") || geoLower.includes("finland") || geoLower.includes("stockholm")) {
        geo = "Sweden";
      } else if (geoLower.includes("france") || geoLower.includes("paris")) {
        geo = "France";
      } else if (geoLower.includes("germany") || geoLower.includes("berlin") || geoLower.includes("munich")) {
        geo = "Germany";
      } else {
        geo = geo.split(/[\s\/,\-_]+/)
          .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
          .join(" ");
      }
    }

    // 3. Clean City name formatting
    if (city) {
      city = city.split(/[\s\/,\-_]+/)
        .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
        .join(" ");
    }

    return {
      ...inv,
      geo: geo || "United States",
      stage: stage || "Seed",
      city: city || "",
      notes: notes
    };
  }).filter(Boolean);
};

const deduplicateInvestors = (list) => {
  const cleaned = cleanAndStandardizeInvestors(list);
  const merged = [];
  cleaned.forEach((item) => {
    if (!item) return;
    const isDup = (i) => {
      const linkMatch = item.linkedin && i.linkedin && i.linkedin === item.linkedin;
      const nameMatch = item.name && item.fund && i.name && i.fund &&
                        i.name.toLowerCase() === item.name.toLowerCase() &&
                        i.fund.toLowerCase() === item.fund.toLowerCase();
      return linkMatch || nameMatch;
    };
    const existingIndex = merged.findIndex(isDup);
    if (existingIndex !== -1) {
      merged[existingIndex] = {
        ...merged[existingIndex],
        ...item,
        id: merged[existingIndex].id,
        focus: Array.from(new Set([...(merged[existingIndex].focus || []), ...(item.focus || [])])),
        notes: [merged[existingIndex].notes, item.notes].filter(Boolean).join("\n\n")
      };
    } else {
      merged.push(item);
    }
  });
  return merged;
};

async function extractTextFromPdf(file) {
  if (!window.pdfjsLib) {
    throw new Error("PDF.js library is not loaded. Please verify CDN connection.");
  }
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;
  let text = "";
  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    const strings = content.items.map(item => item.str);
    text += `--- Page ${i} ---\n` + strings.join(" ") + "\n";
  }
  return text;
}

function renderMarkdownToHtml(markdown) {
  if (!markdown) return "";
  
  // Escape HTML tags to prevent XSS (but preserve basic formatting we inject later)
  let html = markdown
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
    
  // 1. Process Horizontal Rules (3 or more hyphens, underscores, or stars)
  html = html.replace(/^\s*([-_*])\1{2,}\s*$/gm, '<hr style="border: none; border-top: 1px solid #E5E5E0; margin: 16px 0;" />');

  // 2. Process Markdown Tables
  const lines = html.split('\n');
  let inTable = false;
  let tableHeader = null;
  let tableRows = [];
  const processedLines = [];

  const renderHtmlTable = (headers, rows) => {
    if (!headers || headers.length === 0) return "";
    const headerHtml = `<thead><tr style="background: #F4F4F0; text-align: left; border-bottom: 2px solid #15171C;">${headers.map(h => `<th style="padding: 8px 10px; font-weight: bold; border-bottom: 2px solid #15171C; color: #15171C; font-family: monospace; font-size: 11px;">${h}</th>`).join('')}</tr></thead>`;
    const rowsHtml = `<tbody>${rows.map(row => `<tr style="border-bottom: 1px solid #E5E5E0;">${row.map(cell => `<td style="padding: 8px 10px; color: #15171C; word-break: break-word; font-family: monospace; font-size: 11px;">${cell}</td>`).join('')}</tr>`).join('')}</tbody>`;
    return `<div style="overflow-x: auto; margin: 16px 0; border: 1px solid #E5E5E0;"><table style="width: 100%; border-collapse: collapse; background: #FFF; font-family: monospace; font-size: 11px;">${headerHtml}${rowsHtml}</table></div>`;
  };

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line.startsWith('|') && line.endsWith('|')) {
      // Split cell contents, discard the leading and trailing empty elements
      const parts = line.split('|').map(p => p.trim()).filter((_, idx, arr) => idx > 0 && idx < arr.length - 1);
      
      if (!inTable) {
        inTable = true;
        tableHeader = parts;
        tableRows = [];
      } else {
        const isSeparator = parts.every(p => p.match(/^:?-+:?$/));
        if (isSeparator) {
          continue;
        } else {
          tableRows.push(parts);
        }
      }
    } else {
      if (inTable) {
        processedLines.push(renderHtmlTable(tableHeader, tableRows));
        inTable = false;
        tableHeader = null;
        tableRows = [];
      }
      processedLines.push(lines[i]);
    }
  }
  if (inTable) {
    processedLines.push(renderHtmlTable(tableHeader, tableRows));
  }
  
  html = processedLines.join('\n');

  // 3. Headings
  html = html.replace(/^### (.*$)/gim, '<h4 style="font-size: 13px; font-weight: 600; margin-top: 10px; margin-bottom: 6px; color: #15171C;">$1</h4>');
  html = html.replace(/^## (.*$)/gim, '<h3 style="font-size: 14px; font-weight: 600; margin-top: 14px; margin-bottom: 8px; color: #15171C; border-bottom: 1px solid #E5E5E0; padding-bottom: 4px;">$1</h3>');
  html = html.replace(/^# (.*$)/gim, '<h2 style="font-size: 16px; font-weight: 700; margin-top: 16px; margin-bottom: 10px; color: #15171C;">$1</h2>');
  
  // 4. Bold
  html = html.replace(/\*\*(.*?)\*\*/g, '<strong style="font-weight: 600; color: #15171C;">$1</strong>');
  
  // 5. Lists
  html = html.replace(/^\s*[-*]\s+(.*$)/gim, '<li style="margin-left: 14px; margin-bottom: 4px; list-style-type: disc; color: #15171C;">$1</li>');
  
  // 6. Paragraph blocks (split by double newlines)
  const blocks = html.split(/\n\s*\n/);
  html = blocks.map(block => {
    const trimmed = block.trim();
    // If it's already a heading, list item, table block, or horizontal rule, don't wrap in <p>
    if (trimmed.startsWith('<h') || trimmed.startsWith('<li') || trimmed.startsWith('<ul') || trimmed.startsWith('<div') || trimmed.startsWith('<hr')) {
      return block;
    }
    // Handle inline newlines as line breaks
    return `<p style="margin-bottom: 8px; line-height: 1.5; color: #15171C;">${block.replace(/\n/g, '<br />')}</p>`;
  }).join('\n');
  
  return html;
}

const RenderMarkdown = ({ text, style = {}, emptyText = "(empty)" }) => {
  if (!text) return <span style={{ color: FADE, fontStyle: "italic" }}>{emptyText}</span>;
  return (
    <div 
      style={{ wordBreak: "break-word", overflowWrap: "anywhere", ...style }} 
      dangerouslySetInnerHTML={{ __html: renderMarkdownToHtml(text) }}
    />
  );
};

function cleanCompanyNameForMatching(name) {
  if (!name) return "";
  let cleaned = name.replace(/\([^)]*\)/g, "");
  cleaned = cleaned.replace(/\b(inc|ltd|llc|co|corp|ab|gmbh|sa|s\.a\.)\b/gi, "");
  return cleaned.replace(/\s+/g, " ").trim();
}

function getCompanyTags(c, founderProfiles = []) {
  const compTags = c.tags || [];
  const matchingProfiles = founderProfiles.filter(p => {
    const cleanCompName = (name) => (name || "").toLowerCase().replace(/[^a-z0-9]/g, "").trim();
    if (p.company && cleanCompName(p.company) === cleanCompName(c.name)) {
      return true;
    }
    if (c.founders && c.founders.length > 0) {
      return c.founders.some(f => {
        const cleanName = (n) => (n || "").toLowerCase().replace(/[^a-z0-9]/g, "").trim();
        const pClean = cleanName(p.name);
        const fClean = cleanName(f.name);
        return pClean.includes(fClean) || fClean.includes(pClean);
      });
    }
    return false;
  });
  const founderTags = matchingProfiles.flatMap(p => p.tags || []);
  return Array.from(new Set([...compTags, ...founderTags]));
}

function getMatchTokens(name) {
  if (!name) return [];
  const cleaned = cleanCompanyNameForMatching(name).toLowerCase();
  const rawTokens = cleaned.split(/[\s,.\-\/]+/);
  const stopWords = new Set(["capital", "ventures", "partners", "technologies", "solutions", "group", "labs", "networks", "holdings", "advisors", "associates", "fund", "funds", "management", "consulting", "services", "limited", "co", "and", "the", "a", "of", "in", "to", "bnvt", "x", "vs", "with", "for", "meeting", "call", "intro", "update", "catchup", "chat"]);
  return rawTokens.filter(t => t.length > 2 && !stopWords.has(t));
}

async function callGranola(url, method = "GET") {
  const apiKey = (localStorage.getItem("granola_api_key") || "").trim();
  if (!apiKey) return null;
  
  const response = await fetch("/api/granola", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Granola-API-Key": apiKey
    },
    body: JSON.stringify({ url, method })
  });
  
  if (!response.ok) {
    const errText = await response.text();
    let msg = errText;
    if (response.status === 404) {
      msg = "Resource or endpoint not found. Please verify your Granola API key matches a valid workspace/folder connector in settings.";
    }
    throw new Error(`Granola API error (${response.status}): ${msg}`);
  }
  return response.json();
}

function isThinOrPlaceholder(val) {
  if (!val) return true;
  if (typeof val !== "string") return false;
  if (val.trim().length < 80) return true;
  const lower = val.toLowerCase();
  return (
    lower.includes("fabricate") ||
    lower.includes("boilerplate") ||
    lower.includes("generic placeholder") ||
    lower.includes("provide details") ||
    lower.includes("no identifying information") ||
    lower.includes("no meeting context") ||
    lower.includes("undefined") ||
    lower.includes("missing information") ||
    lower.includes("boilerplate template")
  );
}

async function refineSingleSection(company, sectionName, sectionDescription, existingValue) {
  let granolaContext = "";
  try {
    granolaContext = await getGranolaContextForCompany(company.name, company.url, company.granolaNotes);
  } catch (e) {
    console.warn("Failed to get Granola context for refinement:", e);
  }
  const foundersList = (company.founders || []).map(f => `${f.name}${f.linkedin ? ` (LinkedIn: ${f.linkedin})` : ""}`).join(", ");
  const notesText = (company.notes || []).map((n) => "- " + n.text).join("\n");
  
  const prompt = `You are a Senior Venture Capital Investment Analyst.
We need to generate a highly detailed, straight-to-the-point, and custom section for our pipeline company:
Company Name: ${company.name}
One-liner: ${company.oneLiner}
Sector: ${company.sector}
Stage: ${company.stage}
Geographics: ${company.geo || ""}
Founders: ${foundersList || "(none listed)"}
Overview product: ${company.overview?.product || ""}
Overview market: ${company.overview?.market || ""}
Overview traction: ${company.overview?.traction || ""}
Proprietary context notes & Meeting Context:
${notesText || "(none)"}
${granolaContext || ""}

We are compiling a detailed document, and we need you to write/refine the following section:
Section Name: ${sectionName}
Description of what this section must cover: ${sectionDescription}

CRITICAL RULES:
1. The response MUST be highly specific, straight-to-the-point, analytical, and tailored strictly to ${company.name}'s actual product, vertical, and business.
2. CRITICAL SECTOR ACCURACY RULE: Tailor the analysis strictly to the company's actual sector (e.g., spatial intelligence/robotics for Staer, stablecoin payments for Mural Pay). Do NOT assume or write about AI agents or generative AI unless explicitly specified.
3. Use web search to verify facts, retrieve news, founders, and market details. Do NOT complain or say you lack context. If no details are found, extrapolate logical business details based on the industry and one-liner.
4. Respond ONLY with the text content for this section. Do NOT include any JSON formatting, markdown code fences, intro, or outro. Start directly with the content. Ensure it is at least 3-4 sentences of dense analytical detail, with no placeholders or boilerplate.`;

  try {
    const res = await callClaude(prompt, true, "light");
    return res.trim().replace(/^```|```$/g, "");
  } catch (err) {
    console.error(`Refinement failed for section ${sectionName}:`, err);
    return existingValue || `Detailed analysis of ${sectionName} for ${company.name} (generation fell back).`;
  }
}

async function getGranolaContextForCompany(name, companyUrl, savedNotes) {
  if (savedNotes && Array.isArray(savedNotes) && savedNotes.length > 0) {
    const contextBlocks = [];
    for (const note of savedNotes) {
      const attendeesList = (note.attendees || []).map(a => a.name || a.email).join(", ");
      const dateStr = note.calendar_event?.scheduled_start_time
        ? new Date(note.calendar_event.scheduled_start_time).toLocaleDateString()
        : "";
      contextBlocks.push(`=== GRANOLA MEETING NOTE: ${note.calendar_event?.event_title || note.title || "Meeting Note"} (${dateStr}) ===
Key Attendees: ${attendeesList}
Summary:
${note.summary_markdown || note.summary_text || "No summary available."}
Transcript Snippet:
${note.transcript ? note.transcript.map(line => `[${line.speaker || 'Speaker'}]: ${line.text}`).join("\n") : "No transcript details available."}`);
    }
    return `\n\nProprietary context from founder meeting notes (Granola):\n` + contextBlocks.join("\n\n");
  }
  return "";
}

function initializeDefaultCredsDeck(companyName) {
  return {
    slide1: {
      title: `${companyName} Investment Thesis`,
      subtitle: "Investment Rationale"
    },
    slide2: {
      tag: "01. INVESTMENT THESIS",
      title: `Investment Thesis: ${companyName}`,
      blocks: [{ type: "paragraph", value: "" }]
    },
    slide3: {
      tag: "02. CORE STRENGTHS",
      title: `Core Strengths of ${companyName}`,
      blocks: [{ type: "list", value: [] }]
    },
    slide4: {
      tag: "03. MARKET ASSESSMENT",
      title: `Market Assessment for ${companyName}`,
      blocks: [{ type: "paragraph", value: "" }]
    }
  };
}

function mergeCredsDeck(parsed, companyName) {
  const defaults = initializeDefaultCredsDeck(companyName);
  const deck = { ...defaults };
  
  if (parsed.slide1) deck.slide1 = parsed.slide1;
  if (parsed.slide2) deck.slide2 = parsed.slide2;
  if (parsed.slide3) deck.slide3 = parsed.slide3;
  if (parsed.slide4) deck.slide4 = parsed.slide4;
  
  return deck;
}

