  const handleUploadAssets = async (files) => {
    if (!files || files.length === 0) return;
    const fileList = Array.from(files);
    setIngestStatus(`Uploading ${fileList.length} assets...`);
    const newAssets = [...(c.assets || [])];
    let failedCount = 0;

    for (let i = 0; i < fileList.length; i++) {
      const file = fileList[i];
      setIngestStatus(`Uploading asset ${i + 1}/${fileList.length}: ${file.name}...`);
      try {
        const uploaded = await uploadAssetFile(file);
        newAssets.push(uploaded);
      } catch (err) {
        console.error("Upload failed for file: " + file.name, err);
        setErr(`Upload failed for ${file.name}: ` + err.message);
        failedCount++;
      }
    }
    
    update({ assets: newAssets });
    if (failedCount === 0) {
      setIngestStatus(`Successfully uploaded ${fileList.length} files.`);
    } else {
      setIngestStatus(`Upload completed: ${fileList.length - failedCount} succeeded, ${failedCount} failed.`);
    }
  };

  const handleUploadVdrs = async (files) => {
    if (!files || files.length === 0) return;
    const fileList = Array.from(files);
    setIngestStatus(`Ingesting ${fileList.length} VDR documents...`);
    const newDataRoom = [...(c.dataRoom || [])];
    let failedCount = 0;

    for (let i = 0; i < fileList.length; i++) {
      const file = fileList[i];
      setIngestStatus(`Uploading VDR ${i + 1}/${fileList.length}: ${file.name}...`);
      try {
        const uploaded = await uploadAssetFile(file);
        setIngestStatus(`Extracting text from VDR ${i + 1}/${fileList.length}: ${file.name}...`);
        const extractRes = await fetch("/api/extract_text", {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({ url: uploaded.url })
        });
        const extractData = await extractRes.json();
        if (!extractData.success) {
          throw new Error(extractData.error || "Text extraction failed");
        }
        const dataRoomDoc = {
          name: uploaded.name,
          url: uploaded.url,
          text: extractData.text,
          ts: uploaded.ts
        };
        newDataRoom.push(dataRoomDoc);
      } catch (err) {
        console.error("VDR Ingestion failed for file: " + file.name, err);
        setErr(`VDR upload failed for ${file.name}: ` + err.message);
        failedCount++;
      }
    }

    update({ dataRoom: newDataRoom });
    if (failedCount === 0) {
      setIngestStatus(`Successfully ingested ${fileList.length} VDR documents.`);
    } else {
      setIngestStatus(`VDR Ingest completed: ${fileList.length - failedCount} succeeded, ${failedCount} failed.`);
    }
  };

