  // ---- Reference Check Tracker States, Generators & Exporters ----
  const [generatingTracker, setGeneratingTracker] = useState(false);
  const [trackerErr, setTrackerErr] = useState("");
  const [isEditingTracker, setIsEditingTracker] = useState(false);
  const [editContacts, setEditContacts] = useState([]);
  const [outreachReferenceContact, setOutreachReferenceContact] = useState(null);
  const [outreachReferenceCopied, setOutreachReferenceCopied] = useState(false);

  const getReferenceOutreachBlurb = (contact) => {
    if (!contact) return "";
    const firstName = contact.name ? contact.name.trim().split(" ")[0] : "there";
    const sector = c.sector || "[sector]";
    
    const getFirstSentence = (text) => {
      if (!text) return "";
      const match = text.match(/^[^.!?]+[.!?]/);
      return match ? match[0] : text;
    };
    
    const problemText = c.marketStudy?.problemThesis
      ? getFirstSentence(c.marketStudy.problemThesis)
      : c.oneLiner || "[problem that the startup is solving]";
      
    const productOneLiner = c.oneLiner || "[one liner of the product of the startup in question]";
    
    return `Hi ${firstName},

Hope you're well. I invest at BNVT Capital, an early-stage AI fund spun out of Hedosophia and the Gates Foundation.

We back ${sector}, and we're currently digging into ${problemText}

We've been having some great conversations and would value your perspective: we're after hands-on expertise, as we are looking to back ${productOneLiner}.

Would you have 15 minutes in the coming days? Happy to work around your schedule.`;
  };

  useEffect(() => {
    if (c.referenceTracker) {
      setEditContacts(c.referenceTracker.contacts || []);
    } else {
      setEditContacts([]);
    }
  }, [c.referenceTracker, c.id]);

  const saveTracker = () => {
    update({
      referenceTracker: {
        contacts: editContacts
      }
    });
    setIsEditingTracker(false);
  };

  const addTrackerContact = () => {
    setEditContacts([
      ...editContacts,
      {
        id: uid(),
        category: "Potential Customer",
        companyName: "",
        name: "",
        linkedin: "",
        referenceNotes: "",
        userNotes: "",
        verificationStatus: "unverified"
      }
    ]);
  };

  const removeTrackerContact = (id) => {
    setEditContacts(editContacts.filter(item => item.id !== id));
  };

  const runReferenceTracker = async (targetCompany = c) => {
    if (!targetCompany || typeof targetCompany !== "object" || !targetCompany.name || typeof targetCompany.preventDefault === "function") {
      targetCompany = c;
    }
    setGeneratingTracker(true);
    setTrackerErr("");
    try {
      let granolaContext = "";
      try {
        granolaContext = await getGranolaContextForCompany(targetCompany.name, targetCompany.url, targetCompany.granolaNotes);
      } catch (e) {
        console.warn("Failed to get Granola context for reference tracker:", e);
      }
      const notesText = (targetCompany.notes || []).map((n) => "- " + n.text).join("\n");
      const prompt = `You are a principal investment analyst at BNVT Capital, a premium early-stage AI venture capital fund.
We are conducting due diligence on our pipeline company:
Company Name: ${targetCompany.name}
One-liner: ${targetCompany.oneLiner}
Sector: ${targetCompany.sector}
Stage: ${targetCompany.stage}
Product Details: ${targetCompany.overview?.product || ""}
Market Context: ${targetCompany.overview?.market || ""}
Proprietary Notes & Meeting Context:
${notesText || "(none)"}
${granolaContext || ""}

Based on this information, perform web search and industry research to compile an extensive Reference Check Tracker:
CRITICAL RULES:
1. All sourcing details (Existing/Potential Customers, Experts, Investors) MUST be directly relevant to ${targetCompany.name}'s specific sector, vertical, and business model. Do not include generic, unrelated contacts.
2. For "Existing Customer" (10 contacts) and "Potential Customer" (20 contacts), list target companies that operate specifically in the startup's buying vertical (e.g., if target sells logistics AI, list logistics/supply-chain enterprises; if healthcare, list hospital networks).
3. All names, roles, and profiles must be highly realistic, factual, and strictly specific.
1. "Existing Customer" (Provide exactly 10 contacts): Target companies that currently buy, pilot, or use products from ${targetCompany.name} (or if the company is in early stealth, identify real target customers who are active buyers of such solutions in this sector). For each, identify a high-quality relevant point of contact (typically CTO, Head of IT, Head of Innovation, or specialized Director) with their realistic LinkedIn URL.
2. "Potential Customer" (Provide exactly 20 contacts): Target enterprises or organizations in relevant verticals who are prospective buyers for ${targetCompany.name}'s technology. For each, identify a relevant buyer persona title (e.g. CISO, VP Operations, Head of Robotics) with a realistic individual's name and LinkedIn URL.
3. "Industry Expert" (Provide exactly 10 contacts): 10 notable experts, university professors, researchers, or senior consultants in the target field (e.g. specialized computer vision researchers, LLM optimization researchers, industrial automation experts) with names and LinkedIn URLs.
4. "Existing Investor" (Provide 5 to 10 contacts): Venture capital partners, angel investors, or target co-investors active in this sector, along with partner names and LinkedIn URLs.

Respond ONLY with valid JSON in this exact structure, with no markdown fences, no preamble, and no explanation:
{
  "contacts": [
    {
      "category": "Existing Customer",
      "companyName": "Tesla",
      "name": "Drew Baglino",
      "linkedin": "https://www.linkedin.com/in/drewbaglino"
    }
  ]
}

Double check that the "contacts" array contains exactly:
- 10 items of category "Existing Customer"
- 20 items of category "Potential Customer"
- 10 items of category "Industry Expert"
- 5 to 10 items of category "Existing Investor"
Total contacts must be 45 to 50. Use realistic, high-quality industry names, real points of contact where searchable, and realistic LinkedIn URLs.`;

      const outText = await callClaude(prompt, true);
      const out = parseJSON(outText);
      const contacts = (out.contacts || []).map(item => ({
        id: uid(),
        category: item.category || "Potential Customer",
        companyName: item.companyName || item.company || item.company_name || "",
        name: item.name || item.contact || item.individual || "",
        linkedin: item.linkedin || item.linkedin_url || item.url || "",
        referenceNotes: "",
        verificationStatus: "unverified"
      }));

      let validContacts = contacts.filter(contact => {
        if (!contact.companyName || !contact.name) return false;
        if (isThinOrPlaceholder(contact.companyName) || isThinOrPlaceholder(contact.name)) return false;
        return true;
      });

      if (validContacts.length < 40) {
        console.log(`Only found ${validContacts.length} valid contacts. Running recursive generation to retrieve additional contacts.`);
        const counts = {
          "Existing Customer": 0,
          "Potential Customer": 0,
          "Industry Expert": 0,
          "Existing Investor": 0
        };
        validContacts.forEach(c => {
          if (counts[c.category] !== undefined) counts[c.category]++;
        });

        const targetCounts = {
          "Existing Customer": 10,
          "Potential Customer": 20,
          "Industry Expert": 10,
          "Existing Investor": 7
        };

        const needed = [];
        for (const cat in targetCounts) {
          const diff = targetCounts[cat] - counts[cat];
          if (diff > 0) {
            needed.push(`${diff} contacts for category "${cat}"`);
          }
        }

        if (needed.length > 0) {
          const refinePrompt = `We need additional highly specific, realistic and verified due diligence contacts for ${targetCompany.name} (${targetCompany.sector}).
Currently we have:
${validContacts.map(c => `- [${c.category}] ${c.companyName} / ${c.name} (${c.linkedin})`).join("\n")}

Please generate exactly:
${needed.join("\n")}

Respond ONLY with valid JSON in this exact structure:
{
  "contacts": [
    {
      "category": "Existing Customer|Potential Customer|Industry Expert|Existing Investor",
      "companyName": "...",
      "name": "...",
      "linkedin": "..."
    }
  ]
}`;
          try {
            const extraText = await callClaude(refinePrompt, true);
            const extraOut = parseJSON(extraText);
            const extraContacts = (extraOut.contacts || []).map(item => ({
              id: uid(),
              category: item.category || "Potential Customer",
              companyName: item.companyName || item.company || item.company_name || "",
              name: item.name || item.contact || item.individual || "",
              linkedin: item.linkedin || item.linkedin_url || item.url || "",
              referenceNotes: "",
              verificationStatus: "unverified"
            })).filter(c => c.companyName && c.name && !isThinOrPlaceholder(c.companyName) && !isThinOrPlaceholder(c.name));

            validContacts = [...validContacts, ...extraContacts];
          } catch (e) {
            console.warn("Failed to retrieve additional contacts recursively:", e);
          }
        }
      }

      update({ referenceTracker: { contacts: validContacts } });
      return { contacts: validContacts };
    } catch (e) {
      setTrackerErr("Generation failed: " + e.message);
      throw e;
    } finally {
      setGeneratingTracker(false);
    }
  };

  const exportTrackerExcel = () => {
    if (!c.referenceTracker) return;
    const contactsList = c.referenceTracker.contacts || [];
    
    let rowsHtml = contactsList.map(contact => `
      <tr>
        <td style="border: 1px solid #000;">${contact.category || ""}</td>
        <td style="border: 1px solid #000;">${contact.companyName || ""}</td>
        <td style="border: 1px solid #000;">${contact.name || ""}</td>
        <td style="border: 1px solid #000;">${contact.linkedin || ""}</td>
        <td style="border: 1px solid #000;">${contact.referenceNotes || ""}</td>
      </tr>
    `).join("");

    const html = `
      <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
      <head>
        <!--[if gte mso 9]>
        <xml>
          <x:ExcelWorkbook>
            <x:ExcelWorksheets>
              <x:ExcelWorksheet>
                <x:Name>Reference Tracker</x:Name>
                <x:WorksheetOptions>
                  <x:DisplayGridlines/>
                </x:WorksheetOptions>
              </x:ExcelWorksheet>
            </x:ExcelWorksheets>
          </x:ExcelWorkbook>
        </xml>
        <![endif]-->
        <style>
          td { font-family: 'Courier New', monospace; font-size: 10pt; }
          .header { font-weight: bold; background-color: #FFFFFF; }
          .title { font-size: 14pt; font-weight: bold; }
        </style>
      </head>
      <body>
        <table>
          <tr>
            <td colspan="5" class="title" style="font-size: 14pt; font-weight: bold;">BNVT Capital - Reference Check Tracker</td>
          </tr>
          <tr>
            <td colspan="5" style="font-style: italic;">Subject Company: ${c.name}</td>
          </tr>
          <tr><td></td></tr>
          <tr class="header">
            <td style="border: 1px solid #000; font-weight: bold; width: 150px;">Category</td>
            <td style="border: 1px solid #000; font-weight: bold; width: 200px;">Company Name</td>
            <td style="border: 1px solid #000; font-weight: bold; width: 180px;">Name of Individual</td>
            <td style="border: 1px solid #000; font-weight: bold; width: 300px;">LinkedIn Profile URL</td>
            <td style="border: 1px solid #000; font-weight: bold; width: 250px;">References</td>
          </tr>
          ${rowsHtml}
        </table>
      </body>
      </html>
    `;
    const blob = new Blob(['\ufeff' + html], { type: 'application/vnd.ms-excel' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${c.name.replace(/\s+/g, '_')}_Reference_Tracker.xls`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // ---- Verification System for LinkedIn URLs ----
  const [verifyingAll, setVerifyingAll] = useState(false);
  const [verifiedCount, setVerifiedCount] = useState(0);

  const verifyContacts = async (targetIds) => {
    if (targetIds.length === 0) return;
    
    // Determine which list we are editing/verifying
    const currentList = isEditingTracker ? editContacts : (c.referenceTracker?.contacts || []);
    
    // Set status of target contacts to verifying
    const initialList = currentList.map(item => {
      if (targetIds.includes(item.id)) {
        return { ...item, verificationStatus: "verifying" };
      }
      return item;
    });
    
    if (isEditingTracker) {
      setEditContacts(initialList);
    } else {
      update({ referenceTracker: { contacts: initialList } });
    }

    setVerifyingAll(true);
    setVerifiedCount(0);
    setTrackerErr("");

    try {
      const toVerify = initialList.filter(item => targetIds.includes(item.id));
      const batchSize = 5;
      let updatedContacts = [...initialList];

      for (let i = 0; i < toVerify.length; i += batchSize) {
        const batch = toVerify.slice(i, i + batchSize);
        
        const prompt = `You are a professional due diligence research assistant at BNVT Capital.
We have a list of reference check contacts with names, current companies, and currently recorded LinkedIn URLs.
Some of these LinkedIn URLs might be wrong, dead (redirecting to nothing / 404), or hallucinated.

For each contact, search the web to verify if their LinkedIn URL is correct and active.
Instructions:
1. Search the web for the person's name and company (e.g. "[name] [company] linkedin") to check their real active profile.
2. Compare the search results with the current URL.
3. If the current URL is correct and points to their active profile, return it.
4. If the current URL is incorrect/dead/redirects to nothing, replace it with the correct active URL from search results.
5. If you cannot find any active LinkedIn profile, set the URL to null.

Here are the contacts to verify:
${batch.map((c, idx) => `${idx + 1}. ID: ${c.id} | Name: ${c.name} | Company: ${c.companyName} | Current URL: ${c.linkedin}`).join("\n")}

Respond ONLY with valid JSON in this exact structure, with no markdown fences, no preamble, and no explanation:
{
  "results": [
    {
      "id": "contact_id",
      "status": "verified" or "corrected" or "not_found",
      "linkedin": "correct_or_new_url_or_null"
    }
  ]
}

Double check that every input contact ID is included in the output "results" list.`;

        const outText = await callClaude(prompt, true);
        const out = parseJSON(outText);
        const results = out.results || [];

        updatedContacts = updatedContacts.map(item => {
          const res = results.find(r => r.id === item.id);
          if (res) {
            let finalUrl = item.linkedin;
            let finalStatus = "not_found";

            if (res.status === "verified") {
              finalStatus = "verified";
            } else if (res.status === "corrected" && res.linkedin) {
              finalUrl = res.linkedin;
              finalStatus = "corrected";
            } else if (res.status === "not_found" || !res.linkedin) {
              finalStatus = "not_found";
            }

            return {
              ...item,
              linkedin: finalUrl,
              verificationStatus: finalStatus
            };
          }
          return item;
        });

        if (isEditingTracker) {
          setEditContacts(updatedContacts);
        } else {
          update({ referenceTracker: { contacts: updatedContacts } });
        }
        
        setVerifiedCount(prev => prev + batch.length);
      }
    } catch (e) {
      setTrackerErr("Verification failed: " + e.message);
      // Reset remaining verifying contacts to unverified
      const resetList = (isEditingTracker ? editContacts : (c.referenceTracker?.contacts || [])).map(item => {
        if (item.verificationStatus === "verifying") {
          return { ...item, verificationStatus: "unverified" };
        }
        return item;
      });
      if (isEditingTracker) {
        setEditContacts(resetList);
      } else {
        update({ referenceTracker: { contacts: resetList } });
      }
    } finally {
      setVerifyingAll(false);
    }
  };

