  const calculateReturnScenario = (exitVal, ticket, valuation, dilution) => {
    const tVal = parseFloat(ticket) || 0;
    const pVal = parseFloat(valuation) || 0;
    const dVal = parseFloat(dilution) || 0;
    const eVal = parseFloat(exitVal) || 0;

    if (!pVal || !tVal) {
      return { entryOwnership: 0, exitOwnership: 0, positionValue: 0, multiple: 0, fundReturned: 0 };
    }

    const entryOwnership = (tVal / pVal) * 100;
    const exitOwnership = entryOwnership * (1 - dVal / 100);
    const positionValue = eVal * (exitOwnership / 100);
    const multiple = tVal > 0 ? positionValue / tVal : 0;
    const fundReturned = (positionValue / 130) * 100;

    return {
      entryOwnership,
      exitOwnership,
      positionValue,
      multiple,
      fundReturned
    };
  };


