    if (!targetCompany || typeof targetCompany !== "object" || !targetCompany.name || typeof targetCompany.preventDefault === "function") {
      targetCompany = c;
    }
    setGeneratingCreds(true);
    setCredsErr("");
    try {
      let granolaContext = "";
      try {
        granolaContext = await getGranolaContextForCompany(targetCompany.name, targetCompany.url, targetCompany.granolaNotes);
      } catch (e) {
        console.warn("Failed to get Granola context for credentials deck:", e);
      }
      const foundersList = (targetCompany.founders || []).map(f => `${f.name}${f.linkedin ? ` (LinkedIn: ${f.linkedin})` : ""}`).join(", ");
      const notesText = (targetCompany.notes || []).map((n) => "- " + n.text).join("\n");
      const prompt = `You are a principal investment analyst.
We need a highly personalized, tailored investment-thesis deck detailing the investment rationale for this target company:
Company Name: ${targetCompany.name}
One-liner: ${targetCompany.oneLiner}
Sector: ${targetCompany.sector}
Stage: ${targetCompany.stage}
Founders: ${foundersList || "(none listed)"}
Product Details: ${targetCompany.overview?.product || ""}
Market Context: ${targetCompany.overview?.market || ""}
Traction Details: ${targetCompany.overview?.traction || ""}
Proprietary Notes & Meeting Context:
${notesText || "(none)"}
${granolaContext || ""}

Based on this information:
CRITICAL RULES:
1. All slide contents MUST be highly customized strictly to ${targetCompany.name}'s actual product, team, and vertical. Avoid general tech descriptions or generic placeholders.
2. CRITICAL SECTOR ACCURACY RULE: You must tailor all contents strictly to the target company's actual sector, product, and vertical. For example, if the company does spatial intelligence/robotics (like Staer) or stablecoin payments/fintech (like Mural Pay), analyze that specific domain. Do NOT write about AI agents, multi-agent coordination, or generative AI unless the target company's profile explicitly specifies that they build those technologies.
3. If web search is available, use it to fetch live facts, but prioritize the company's real profile, founders, and notes. If web search is unavailable or fails, generate slide content strictly based on the provided profile, notes, and metrics.
4. Ensure every word counts. Keep the text extremely concise, sharp, and focused solely on the investment rationale.
5. NO BNVT MENTIONS: Do NOT mention BNVT Capital, BNVT, or BNVT's perspective anywhere in the titles, tags, or blocks. The slides must be entirely focused on the target company and the investment rationale.
6. Rules for content and layout:
   - Make the design minimalist and text-focused. Do NOT suggest or include any charts, graphs, timelines, or photo layouts.
   - All slide contents must be extremely concise and punchy.
   - For each slide, write a slide "tag" (uppercase, short subtitle) and a factual "title" (max 10 words).
   - Slides 2-4 must provide an array of "blocks". Each block is an object representing a paragraph or a list:
     * Paragraph block: { "type": "paragraph", "value": "A single high-impact sentence or short paragraph of at most 40 words." }
     * List block: { "type": "list", "value": ["Bullet 1 (max 15 words)", "Bullet 2 (max 15 words)", ...] }
7. The slide structure MUST follow:
   - slide1 (Cover): Title: "${targetCompany.name} Investment Thesis", Subtitle: "Sector: ${targetCompany.sector} // Stage: ${targetCompany.stage}" (strictly no mention of BNVT).
   - slide2 (Investment Thesis): tag: "01. INVESTMENT THESIS", title: "Investment Thesis for ${targetCompany.name}", blocks: 1-2 paragraph blocks detailing the core thesis, growth tailwinds, and why it represents an outsized outcome.
   - slide3 (Core Strengths): tag: "02. CORE STRENGTHS", title: "Core Strengths of ${targetCompany.name}", blocks: list block with 3-5 high-impact bullets detailing what makes this team, product, or traction exceptional.
   - slide4 (Market Assessment): tag: "03. MARKET ASSESSMENT", title: "Market Assessment for ${targetCompany.name}", blocks: paragraph block analyzing the market dynamics, or a list block detailing tailwinds, industry shifts, or market scale.

CRITICAL FORMATTING REQUIREMENT: You MUST respond with a single, valid JSON object matching the exact schema below. Do not include any conversational preamble, introduction, explanation, markdown fences (like triple-backtick json), or postscript. Apologies are strictly forbidden. The response must start with '{' and end with '}'.

{
  "slide1": {
    "title": "${targetCompany.name} Investment Thesis",
    "subtitle": "Sector: ${targetCompany.sector} // Stage: ${targetCompany.stage}"
  },
  "slide2": {
    "tag": "01. INVESTMENT THESIS",
    "title": "Investment Thesis for ${targetCompany.name}",
    "blocks": [
      { "type": "paragraph", "value": "..." }
    ]
  },
  "slide3": {
    "tag": "02. CORE STRENGTHS",
    "title": "Core Strengths of ${targetCompany.name}",
    "blocks": [
      { "type": "list", "value": ["Bullet 1", "Bullet 2"] }
    ]
  },
  "slide4": {
    "tag": "03. MARKET ASSESSMENT",
    "title": "Market Assessment for ${targetCompany.name}",
    "blocks": [
      { "type": "paragraph", "value": "..." }
    ]
  }
}`;

      let outText = "";
      let out;
      try {
        outText = await callClaude(prompt, true);
        out = parseJSON(outText);
      } catch (searchErr) {
        console.warn("Credentials deck generation with search failed, retrying without search. Error:", searchErr);
        fetch("/api/log_error", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            message: `Creds deck search generation failed, falling back. Error: ${searchErr.message}. Raw response: ${outText || ""}`
          })
        }).catch(() => {});
        
        outText = await callClaude(prompt, false);
        out = parseJSON(outText);
      }
      
      const creds = mergeCredsDeck(out, targetCompany.name);

      // Recursive refinement checks for thin or placeholder slides
      if (!creds.slide2.blocks || creds.slide2.blocks.length === 0 || isThinOrPlaceholder(creds.slide2.blocks[0]?.value)) {
        const val = await refineSingleSection(targetCompany, "Investment Thesis Slide Rationale", "A detailed, straight-to-the-point paragraph of exactly 2-3 sentences explaining the macro problem, B2B mechanics, and why this represents an outsized exit outcome.", creds.slide2.blocks?.[0]?.value || "");
        creds.slide2.blocks = [{ type: "paragraph", value: val }];
      }
      
      if (!creds.slide3.blocks || creds.slide3.blocks.length === 0 || !creds.slide3.blocks[0]?.value || creds.slide3.blocks[0].value.length < 3) {
        const rawBullets = await refineSingleSection(targetCompany, "Core Strengths Slide Bullet Points", "A bulleted list of 3-5 high-impact bullet points (each starting with a dash or bullet) highlighting the exceptional founder pedigree, technical wedge, and commercial validation. Do not include any intro/outro.", "");
        const bullets = rawBullets.split("\n").map(line => line.trim().replace(/^[-•*]\s*/, "")).filter(Boolean);
        creds.slide3.blocks = [{ type: "list", value: bullets }];
      }

      if (!creds.slide4.blocks || creds.slide4.blocks.length === 0 || isThinOrPlaceholder(creds.slide4.blocks[0]?.value)) {
        const val = await refineSingleSection(targetCompany, "Market Assessment Slide Rationale", "A detailed paragraph of 2-3 sentences analyzing the market dynamics, tailwinds, industry shifts, or market scale.", creds.slide4.blocks?.[0]?.value || "");
        creds.slide4.blocks = [{ type: "paragraph", value: val }];
      }

      update({ credsDeck: creds });
      setEditedCredsDeck(creds);
      return creds;
    } catch (e) {
      setCredsErr("Generation failed: " + e.message);
      throw e;
    } finally {
      setGeneratingCreds(false);
    }
