  const downloadCredsPPTX = () => {
    if (!c.credsDeck) return;
    const deck = c.credsDeck;
    
    // Initialize PptxGenJS
    let pptx = new PptxGenJS();
    pptx.layout = 'LAYOUT_16x9';
    
    // Define brand colors
    const BG_COLOR = 'FFFFFF';      // Cream/Paper background
    const CARD_COLOR = 'FFFFFF';    // White panel cards
    const ACCENT_COLOR = '000000';  // BNVT Blue
    const TEXT_COLOR = '000000';    // Dark Ink
    const FADE_COLOR = '6B6E76';    // Fade Grey
    const GREEN_COLOR = '000000';   // SOTA Green
    const LIGHT_BLUE = 'D3D3D3';    // Accent Blue
    const BEIGE_COLOR = 'CCCCCC';   // Light Beige
    
    // Helper to add slide background and standard headers/footers
    const createBaseSlide = (slideNum, tagLabel) => {
      let slide = pptx.addSlide();
      slide.background = { fill: BG_COLOR };
      
      // Top header
      slide.addText(`${c.name.toUpperCase()} // INVESTMENT RATIONALE`, {
        x: 0.5, y: 0.25, w: 4.0, h: 0.3,
        fontSize: 10,
        fontFace: 'IBM Plex Mono',
        color: ACCENT_COLOR,
        bold: true
      });
      slide.addText("CONFIDENTIAL", {
        x: 5.0, y: 0.25, w: 4.5, h: 0.3,
        fontSize: 10,
        fontFace: 'IBM Plex Mono',
        color: FADE_COLOR,
        align: 'right',
        bold: true
      });
      
      // Slide Tag
      slide.addText(tagLabel, {
        x: 0.5, y: 0.7, w: 9.0, h: 0.25,
        fontSize: 10,
        fontFace: 'IBM Plex Mono',
        color: ACCENT_COLOR,
        bold: true
      });
      
      // Slide Title
      slide.addText(deck[`slide${slideNum}`]?.title || "", {
        x: 0.5, y: 0.95, w: 9.0, h: 0.6,
        fontSize: 22,
        fontFace: 'Georgia',
        color: TEXT_COLOR,
        bold: true
      });
      
      // Footer page number
      slide.addText(`Slide ${slideNum} of 4`, {
        x: 8.5, y: 5.2, w: 1.0, h: 0.3,
        fontSize: 9,
        fontFace: 'IBM Plex Mono',
        color: FADE_COLOR,
        align: 'right'
      });
      
      slide.addText("CONFIDENTIAL", {
        x: 0.5, y: 5.2, w: 2.0, h: 0.3,
        fontSize: 9,
        fontFace: 'IBM Plex Mono',
        color: FADE_COLOR
      });
      
      return slide;
    };
    
    // --- Slide 1: Cover ---
    let s1 = pptx.addSlide();
    s1.background = { fill: BG_COLOR };
    // Large text
    s1.addText("INVESTMENT THESIS", {
      x: 1.0, y: 1.6, w: 8.0, h: 0.5,
      fontSize: 14,
      fontFace: 'IBM Plex Mono',
      color: ACCENT_COLOR,
      bold: true,
      charSpacing: 3
    });
    // Main Title
    s1.addText(deck.slide1?.title || "", {
      x: 1.0, y: 2.3, w: 8.0, h: 1.4,
      fontSize: 32,
      fontFace: 'Georgia',
      color: TEXT_COLOR,
      bold: true
    });
    // Subtitle
    s1.addText(deck.slide1?.subtitle || "", {
      x: 1.0, y: 3.8, w: 8.0, h: 0.8,
      fontSize: 16,
      fontFace: 'Georgia',
      color: FADE_COLOR,
      italic: true
    });
    // Date/Confidentiality
    s1.addText("CONFIDENTIAL // INVESTMENT RATIONALE", {
      x: 1.0, y: 4.8, w: 8.0, h: 0.4,
      fontSize: 10,
      fontFace: 'IBM Plex Mono',
      color: ACCENT_COLOR,
      bold: true
    });
    
    // --- Slides 2 to 4: Dynamic content ---
    const slidesData = [
      { num: 2, key: "slide2", fallbackLabel: "01. INVESTMENT THESIS" },
      { num: 3, key: "slide3", fallbackLabel: "02. CORE STRENGTHS" },
      { num: 4, key: "slide4", fallbackLabel: "03. MARKET ASSESSMENT" }
    ];

    slidesData.forEach((slideInfo) => {
      const slideData = deck[slideInfo.key];
      if (!slideData) return;
      const tagLabel = slideData.tag || slideInfo.fallbackLabel;
      let slide = createBaseSlide(slideInfo.num, tagLabel);

      const blocks = slideData.blocks || [
        { type: "paragraph", value: slideData.content || "" },
        { type: "list", value: slideData.bullets || [] }
      ].filter(b => b.value && (!Array.isArray(b.value) || b.value.length > 0));

      let currentY = 1.7;

      blocks.forEach((block) => {
        if (block.type === 'paragraph' && block.value) {
          const textLength = block.value.length;
          const estHeight = textLength > 100 ? 0.6 : 0.4;
          slide.addText(block.value, {
            x: 0.5, y: currentY, w: 9.0, h: estHeight,
            fontSize: 12,
            fontFace: 'Calibri',
            color: TEXT_COLOR,
            lineSpacing: 16
          });
          currentY += estHeight + 0.25;
        } else if (block.type === 'list' && Array.isArray(block.value)) {
          const listItems = block.value.filter(Boolean);
          if (listItems.length > 0) {
            const bulletData = listItems.map(bullet => ({
              text: bullet,
              options: { bullet: true, fontSize: 11, fontFace: 'Calibri', color: TEXT_COLOR, lineSpacing: 14 }
            }));
            const estHeight = listItems.length * 0.35;
            slide.addText(bulletData, {
              x: 0.5, y: currentY, w: 9.0, h: estHeight
            });
            currentY += estHeight + 0.25;
          }
        } else if (block.type === 'table' && block.headers && block.rows) {
          const pptxTableRows = [];
          
          pptxTableRows.push(
            block.headers.map(h => ({
              text: h,
              options: { bold: true, fill: 'FCFCFC', fontFace: 'Calibri', fontSize: 10, color: TEXT_COLOR }
            }))
          );
          
          block.rows.forEach((row) => {
            pptxTableRows.push(
              row.map(cell => {
                const isTarget = String(cell).toLowerCase().includes(c.name.toLowerCase());
                return {
                  text: cell,
                  options: {
                    fontFace: 'Calibri',
                    fontSize: 9.5,
                    color: TEXT_COLOR,
                    bold: isTarget,
                    fill: isTarget ? 'F5F5F5' : 'FFFFFF'
                  }
                };
              })
            );
          });

          const tableHeight = (pptxTableRows.length) * 0.35;
          slide.addTable(pptxTableRows, {
            x: 0.5, y: currentY, w: 9.0, h: tableHeight,
            border: { pt: 0.5, color: BEIGE_COLOR }
          });
          currentY += tableHeight + 0.25;
        }
      });
    });


    // Save/Download presentation
    pptx.writeFile({ fileName: `${c.name.replace(/\s+/g, "_")}_Investment_Thesis.pptx` });
  };

